<?php
 namespace League\CommonMark\Block\Element; use League\CommonMark\ContextInterface; use League\CommonMark\Cursor; class Heading extends AbstractStringContainerBlock implements InlineContainerInterface { protected $level; public function __construct(int $level, $contents) { parent::__construct(); $this->level = $level; if (!\is_array($contents)) { $contents = [$contents]; } foreach ($contents as $line) { $this->addLine($line); } } public function getLevel(): int { return $this->level; } public function finalize(ContextInterface $context, int $endLineNumber) { parent::finalize($context, $endLineNumber); $this->finalStringContents = \implode("\n", $this->strings->toArray()); } public function canContain(AbstractBlock $block): bool { return false; } public function isCode(): bool { return false; } public function matchesNextLine(Cursor $cursor): bool { return false; } public function handleRemainingContents(ContextInterface $context, Cursor $cursor) { } } 